import { fireEvent, render, screen } from "@testing-library/react";
import { createRef } from "react";
import { describe, expect, it } from "vitest";
import { PasswordInput } from "./PasswordInput.js";

// Renders the presentational input with NO FormProvider, proving it is usable
// standalone (outside of a <Form>).
describe("PasswordInput (presentational)", () => {
  it("masks the value by default (type=password)", () => {
    render(<PasswordInput name="secret" defaultValue="hunter2" />);
    expect(screen.getByDisplayValue("hunter2")).toHaveAttribute(
      "type",
      "password",
    );
  });

  it("offers a reveal toggle that flips the input type and its label", () => {
    render(<PasswordInput name="secret" defaultValue="hunter2" />);
    const toggle = screen.getByRole("button", { name: "Show password" });
    const input = screen.getByDisplayValue("hunter2");
    expect(input).toHaveAttribute("type", "password");
    expect(toggle).toHaveAttribute("aria-pressed", "false");

    fireEvent.click(toggle);
    expect(input).toHaveAttribute("type", "text");
    expect(
      screen.getByRole("button", { name: "Hide password" }),
    ).toHaveAttribute("aria-pressed", "true");
  });

  it("omits the toggle when revealable is false", () => {
    render(<PasswordInput name="secret" revealable={false} />);
    expect(screen.queryByRole("button")).not.toBeInTheDocument();
  });

  it("renders no prefix", () => {
    const { container } = render(<PasswordInput name="secret" />);
    expect(container.querySelector(".prefix")).toBeNull();
  });

  it("wires the toggle to the input via aria-controls", () => {
    const { container } = render(<PasswordInput name="secret" />);
    const toggle = screen.getByRole("button", { name: "Show password" });
    const controlled = toggle.getAttribute("aria-controls");
    expect(controlled).toBeTruthy();
    const input = container.querySelector("input");
    expect(input?.id).toBe(controlled);
  });

  it("forwards a ref to the underlying input", () => {
    const ref = createRef<HTMLInputElement>();
    render(<PasswordInput name="secret" ref={ref} />);
    expect(ref.current).toBeInstanceOf(HTMLInputElement);
  });

  it("supports the disabled state", () => {
    render(<PasswordInput name="secret" defaultValue="x" disabled />);
    expect(screen.getByDisplayValue("x")).toBeDisabled();
  });
});
